import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";const o=JSON.parse(`{"title":"Windows에서 Fabric 업데이트","description":"Windows에서 Fabric을 업데이트하기 위한 단계별 가이드","frontmatter":{"title":"Windows에서 Fabric 업데이트","description":"Windows에서 Fabric을 업데이트하기 위한 단계별 가이드","authors":["IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"ko_kr/players/updating-fabric/windows.md","filePath":"translated/ko_kr/players/updating-fabric/windows.md","lastUpdated":1772272927000}`);var s={name:`ko_kr/players/updating-fabric/windows.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Windows에서 Fabric 업데이트 <a class="header-anchor" href="#h1" aria-label="Permalink to “Windows에서 Fabric 업데이트”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Fabric 설치기 다운로드 <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Fabric 설치기 다운로드”">​</a></h2><p>Fabric 설치기를 <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric 웹사이트</a>에 접속한 후, <code>윈도우용 설치기 다운로드</code> 버튼을 눌러 다운로드하세요. 다운로드하려는 파일 형식은 <code>.exe</code> 입니다.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>공식 마인크래프트 런처에 Java가 내장되어 있기 때문에<code>.exe</code> 형식의 설치기는 Java가 필요하지 않습니다.</p></div><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Fabric 설치기 시작 <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Fabric 설치기 시작”">​</a></h2><p>설치기를 시작하기 전에, 먼저 모든 Minecraft 인스턴스와 Minecrft 런처를 종료해야 합니다.</p><p>설치기를 실행하면, 아래 사진과 같이 실행됩니다:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="&quot;Install&quot;을 강조 표시한 Fabric 설치기" loading="lazy"></p><p>새 게임 버전과 로더 버전이 일치하는지 확인하고 <code>설치</code>를 눌러 업데이트하세요.</p><div class="warning custom-block"><p class="custom-block-title">중요</p><p>설치기 실행중인 경우 &#39;프로필 생성&#39;을 반드시 비활성화하세요.</p></div><h2 id="3-update-launcher-profile" tabindex="-1">3. 마인크래프트 런처에서 프로필 업데이트하기 <a class="header-anchor" href="#3-update-launcher-profile" aria-label="Permalink to “3. 마인크래프트 런처에서 프로필 업데이트하기”">​</a></h2><p>설치가 끝나면, 마인크래프트 런처를 실행하세요. <code>설치 목록</code> 탭으로 이동합니다. Fabric 프로필을 선택하고 아래와 같이 수정합니다:</p><p><img src="/assets/players/updating-fabric.png" alt="Minecraft 런처에서 Fabric 로더 버전을 변경하는 모습" loading="lazy"></p><p>버전을 방금 설치한 Fabric 로더로 선택한 다음, <code>저장</code>을 클릭합니다.</p><h2 id="4-you-re-done" tabindex="-1">4. 업데이트 완료 <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. 업데이트 완료”">​</a></h2><p>위의 과정을 모두 완료했다면 <code>플레이</code> 탭으로 돌아가서, 왼쪽 아래의 버전 선택 메뉴에서 Fabric을 선택한 다음 플레이를 클릭하면 됩니다.</p><p>설치 과정 중 문제가 발생했다면, <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord (영어)</a>의 <code>#player-support</code> 채널에서 도움을 요청할 수 있습니다.</p>`,17)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};